diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index 439a86d951a8..85b137b2c887 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -1706,6 +1706,7 @@ static Value *foldOperationIntoSelectOperand(Instruction &I, SelectInst *SI,
   return Clone;
 }

+
 Instruction *InstCombinerImpl::FoldOpIntoSelect(Instruction &Op, SelectInst *SI,
                                                 bool FoldWithMultiUse) {
   // Don't modify shared select instructions unless set FoldWithMultiUse
@@ -1729,8 +1730,13 @@ Instruction *InstCombinerImpl::FoldOpIntoSelect(Instruction &Op, SelectInst *SI,
   if (auto *CI = dyn_cast<FCmpInst>(SI->getCondition())) {
     if (CI->hasOneUse()) {
       Value *Op0 = CI->getOperand(0), *Op1 = CI->getOperand(1);
-      if ((TV == Op0 && FV == Op1) || (FV == Op0 && TV == Op1))
-        return nullptr;
+      if ((TV == Op0 && FV == Op1) || (FV == Op0 && TV == Op1)) {
+        // The ord and uno predicates check for NaN, not value ordering,
+        // so this is not a min/max idiom. Allow folding in this case.
+        FCmpInst::Predicate Pred = CI->getPredicate();
+        if (Pred != FCmpInst::FCMP_ORD && Pred != FCmpInst::FCMP_UNO)
+          return nullptr;
+      }
     }
   }

@@ -1741,6 +1747,40 @@ Instruction *InstCombinerImpl::FoldOpIntoSelect(Instruction &Op, SelectInst *SI,
   if (!NewTV && !NewFV)
     return nullptr;

+  // Check for the special case where we can eliminate the select entirely.
+  // Pattern: select(fcmp ord X, C, X, K) op where K folds to false and
+  // the operation is an ordered fcmp.
+  // The ordered fcmp already returns false for NaN, making the select redundant.
+  if (match(NewFV, m_Zero()) && !NewTV) {
+    if (auto *FCmp = dyn_cast<FCmpInst>(SI->getCondition())) {
+      if (FCmp->getPredicate() == FCmpInst::FCMP_ORD) {
+        Value *Op0 = FCmp->getOperand(0);
+        Value *Op1 = FCmp->getOperand(1);
+        Value *OtherOp = nullptr;
+        if (TV == Op0)
+          OtherOp = Op1;
+        else if (TV == Op1)
+          OtherOp = Op0;
+
+        if (OtherOp) {
+          if (auto *C = dyn_cast<ConstantFP>(OtherOp)) {
+            if (!C->isNaN()) {
+              if (auto *OpFCmp = dyn_cast<FCmpInst>(&Op)) {
+                if (FCmpInst::isOrdered(OpFCmp->getPredicate())) {
+                  // Clone the fcmp and replace select with TV.
+                  // This creates a detached instruction that InstCombiner can insert.
+                  Instruction *NewInst = OpFCmp->clone();
+                  NewInst->replaceUsesOfWith(SI, TV);
+                  return NewInst;
+                }
+              }
+            }
+          }
+        }
+      }
+    }
+  }
+
   // Create an instruction for the arm that did not fold.
   if (!NewTV)
     NewTV = foldOperationIntoSelectOperand(Op, SI, TV, *this);
@@ -1749,6 +1789,7 @@ Instruction *InstCombinerImpl::FoldOpIntoSelect(Instruction &Op, SelectInst *SI,
   return SelectInst::Create(SI->getCondition(), NewTV, NewFV, "", nullptr, SI);
 }

+
 static Value *simplifyInstructionWithPHI(Instruction &I, PHINode *PN,
                                          Value *InValue, BasicBlock *InBB,
                                          const DataLayout &DL,

